class KaggleGPUOrchestrator:
    def __init__(self, workspace_root: str | Path = ".kaggle_runs") -> None:
        import os
        default = "/tmp/.kaggle_runs" if os.getenv("AWS_LAMBDA_FUNCTION_NAME") else ".kaggle_runs"
        self.workspace_root = Path(workspace_root if workspace_root != ".kaggle_runs" else default)
        self.workspace_root.mkdir(parents=True, exist_ok=True)

    @property
    def configured(self) -> bool:
        return (
            self._kagglehub_available()
            and bool(os.getenv("KAGGLE_API_TOKEN", "").strip())
            and bool(self._dataset_owner())
        )

    def submit_training_run(
        self,
        request: KaggleTrainingRequest,
        training_history: list[TrainingIngestResponse],
        world_model_candidates: list[WorldModelCandidate],
    ) -> KaggleTrainingResponse:
        run_id = f"kaggle_{utc_now().strftime('%Y%m%d_%H%M%S')}_{request.task_type}"
        run_dir = self.workspace_root / run_id
        run_dir.mkdir(parents=True, exist_ok=True)
        payload = self._training_payload(request, training_history, world_model_candidates)
        (run_dir / "training_payload.json").write_text(json.dumps(payload, indent=2), encoding="utf-8")
        (run_dir / "dataset-metadata.json").write_text(json.dumps(self._dataset_metadata(request), indent=2), encoding="utf-8")
        (run_dir / self._notebook_filename(request.task_type)).write_text(
            json.dumps(self._notebook_for_task(request.task_type), indent=2),
            encoding="utf-8",
        )

        if not self._kagglehub_available():
            return KaggleTrainingResponse(
                run_id=run_id,
                status="prepared",
                task_type=request.task_type,
                local_path=str(run_dir),
                detail="kagglehub is not installed; training payload package prepared only.",
            )
        if not os.getenv("KAGGLE_API_TOKEN", "").strip():
            return KaggleTrainingResponse(
                run_id=run_id,
                status="prepared",
                task_type=request.task_type,
                local_path=str(run_dir),
                detail="KAGGLE_API_TOKEN is not configured; training payload package prepared only.",
            )
        if not self._dataset_owner():
            return KaggleTrainingResponse(
                run_id=run_id,
                status="prepared",
                task_type=request.task_type,
                local_path=str(run_dir),
                detail="KAGGLE_DATASET_OWNER or KAGGLE_USERNAME is required to upload the private training dataset.",
            )

        dataset_handle = self._dataset_handle(request)
        try:
            import kagglehub

            kagglehub.dataset_upload(
                dataset_handle,
                str(run_dir),
                version_notes=f"{request.task_type}: {request.notes or 'JIMS-AI training payload'}",
                ignore_patterns=["*.tmp", ".cache/"],
            )
        except Exception as exc:
            return KaggleTrainingResponse(
                run_id=run_id,
                status="failed",
                task_type=request.task_type,
                kernel_ref=dataset_handle,
                local_path=str(run_dir),
                detail=str(exc)[-800:],
            )
        return KaggleTrainingResponse(
            run_id=run_id,
            status="submitted",
            task_type=request.task_type,
            kernel_ref=dataset_handle,
            local_path=str(run_dir),
            detail=(
                "KaggleHub uploaded a private training dataset. Attach this dataset to a Kaggle GPU notebook "
                "or use an existing notebook that reads training_payload.json and writes artifacts."
            ),
        )

    def sync_outputs(self, run: KaggleTrainingResponse, output_root: str | Path = ".kaggle_artifacts") -> KaggleTrainingResponse:
        if not run.kernel_ref:
            return run.model_copy(update={"detail": "No Kaggle dataset or notebook output reference is available for this run."})
        if not self._kagglehub_available() or not os.getenv("KAGGLE_API_TOKEN", "").strip():
            return run.model_copy(update={"detail": "kagglehub or KAGGLE_API_TOKEN is unavailable; cannot sync outputs."})
        output_dir = Path(output_root) / run.run_id
        output_dir.mkdir(parents=True, exist_ok=True)
        try:
            import kagglehub

            downloaded = kagglehub.notebook_output_download(run.kernel_ref, output_dir=str(output_dir), force_download=True)
        except Exception as exc:
            return run.model_copy(
                update={
                    "status": "running",
                    "detail": (
                        "KaggleHub could not download notebook outputs yet. "
                        "If kernel_ref is a dataset handle, run a Kaggle notebook and sync with its notebook output handle. "
                        f"{str(exc)[-500:]}"
                    ),
                }
            )
        return run.model_copy(
            update={
                "status": "completed",
                "local_path": str(downloaded or output_dir),
                "detail": "KaggleHub notebook outputs downloaded and ready for encoder artifact activation.",
            }
        )

    def _training_payload(
        self,
        request: KaggleTrainingRequest,
        training_history: list[TrainingIngestResponse],
        world_model_candidates: list[WorldModelCandidate],
    ) -> dict[str, Any]:
        workspace_id = request.workspace_id
        filtered = [
            item
            for item in training_history
            if workspace_id is None or item.signature.workspace_id in {None, workspace_id}
        ]
        return {
            "task_type": request.task_type,
            "title": request.title,
            "notes": request.notes,
            "workspace_id": workspace_id,
            "created_at": utc_now().isoformat(),
            "sppe_pairs": [item.sppe_training_pair.model_dump(mode="json") for item in filtered],
            "signatures": [item.signature.model_dump(mode="json") for item in filtered],
            "world_model_candidates": [candidate.model_dump(mode="json") for candidate in world_model_candidates],
        }

    def _notebook_for_task(self, task_type: str) -> dict[str, Any]:
        if task_type in {"sppe_renderer_finetune", "sppe_refiner"}:
            return SPPE_RENDERER_TEMPLATE_NOTEBOOK
        return ENCODER_TEMPLATE_NOTEBOOK

    def _notebook_filename(self, task_type: str) -> str:
        if task_type in {"sppe_renderer_finetune", "sppe_refiner"}:
            return "jimsai_sppe_renderer_finetune.ipynb"
        return "jimsai_encoder_finetune.ipynb"

    def _dataset_metadata(self, request: KaggleTrainingRequest) -> dict[str, Any]:
        return {
            "id": self._dataset_handle(request),
            "title": request.title[:80],
            "is_private": True,
            "licenses": [{"name": "CC0-1.0"}],
            "keywords": ["jims-ai", request.task_type, "memory-centric-ai"],
        }

    def _dataset_handle(self, request: KaggleTrainingRequest) -> str:
        return f"{self._dataset_owner()}/{self._slug(f'jimsai-{request.task_type}')}"

    def _dataset_owner(self) -> str:
        owner = os.getenv("KAGGLE_DATASET_OWNER", "").strip() or os.getenv("KAGGLE_USERNAME", "").strip()
        return owner

    def _kagglehub_available(self) -> bool:
        try:
            import kagglehub  # noqa: F401
        except Exception:
            return False
        return True

    def _slug(self, value: str) -> str:
        slug = "".join(char.lower() if char.isalnum() else "-" for char in value)
        slug = "-".join(part for part in slug.split("-") if part)
        return slug[:48] or "jimsai-training"
